export interface Neighbourhood {
  id: string;
  ward: string;
  name: string;
  type: string;
  population: number;
  households: number;
  medianIncome: number;
  medianHomePrice: number;
  sustainableModePct: number;
  affordabilityRatio: number;
  symbol: string;
  row: number;
  col: number;
}

export interface NeighbourhoodStats {
  totalNeighbourhoods: number;
  avgAffordability: number;
  avgIncome: number;
  avgSustainableMode: number;
}

export interface AnalysisResponse {
  summary: string;
  keyHighlights: string[];
  recommendation: string;
}

import { Neighbourhood, NeighbourhoodStats } from '../types';
import { WARD_SYMBOL_MAP, RAW_CSV_DATA } from '../constants';

/**
 * Parses the raw CSV string into structured Neighbourhood objects.
 * Standardizes formatting and handles grid layout calculations.
 */
export const fetchNeighbourhoods = (): Neighbourhood[] => {
  const lines = RAW_CSV_DATA.split('\n');
  const headers = lines[0].split(',');

  const neighbourhoods: Neighbourhood[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // Simple CSV parser for quoted fields
    const regex = /(".*?"|[^",\s]+)(?=\s*,|\s*$)/g;
    const matches = line.matchAll(regex);
    const rowValues = Array.from(matches).map(m => m[0].replace(/"/g, ''));

    if (rowValues.length < 10) continue;

    const [
      id, ward, name, type, popStr, hhStr, incomeStr, priceStr, modeStr, affStr
    ] = rowValues;

    const population = parseInt(popStr.replace(/,/g, '')) || 0;
    const households = parseInt(hhStr.replace(/,/g, '')) || 0;
    const medianIncome = parseInt(incomeStr.replace(/,/g, '')) || 0;
    const medianHomePrice = parseInt(priceStr.replace(/,/g, '')) || 0;
    const sustainableModePct = parseFloat(modeStr) || 0;
    const affordabilityRatio = parseFloat(affStr) || 0;

    neighbourhoods.push({
      id: `${ward}-${name}`,
      ward,
      name,
      type,
      population,
      households,
      medianIncome,
      medianHomePrice,
      sustainableModePct,
      affordabilityRatio,
      symbol: WARD_SYMBOL_MAP[ward] || '??',
      row: 0, // Calculated later
      col: 0  // Calculated later
    });
  }

  // Deduplicate by name and ward
  const uniqueNeighbourhoods = Array.from(new Map(neighbourhoods.map(item => [item.id, item])).values());

  // Calculate Grid Logic
  // Row: Based on Affordability Ratio (0-8)
  uniqueNeighbourhoods.forEach(n => {
    n.row = Math.min(Math.floor(n.affordabilityRatio), 8);
  });

  // Col: Based on Median HHI Percentiles (20 Buckets)
  const sortedByIncome = [...uniqueNeighbourhoods].sort((a, b) => a.medianIncome - b.medianIncome);
  const count = sortedByIncome.length;
  sortedByIncome.forEach((n, idx) => {
    n.col = Math.floor((idx / count) * 20);
  });

  return uniqueNeighbourhoods;
};

export const calculateStats = (data: Neighbourhood[]): NeighbourhoodStats => {
  const count = data.length;
  if (count === 0) return { totalNeighbourhoods: 0, avgAffordability: 0, avgIncome: 0, avgSustainableMode: 0 };

  const sumAffordability = data.reduce((acc, n) => acc + n.affordabilityRatio, 0);
  const sumIncome = data.reduce((acc, n) => acc + n.medianIncome, 0);
  const sumMode = data.reduce((acc, n) => acc + n.sustainableModePct, 0);

  return {
    totalNeighbourhoods: count,
    avgAffordability: sumAffordability / count,
    avgIncome: sumIncome / count,
    avgSustainableMode: sumMode / count
  };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Neighbourhood, AnalysisResponse } from "../types";

/**
 * Uses Gemini 3 Flash to provide a narrative analysis of a selected neighbourhood.
 */
export const analyzeNeighbourhood = async (n: Neighbourhood): Promise<AnalysisResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze this Edmonton neighbourhood:
    - Name: ${n.name}
    - Ward: ${n.ward}
    - Population: ${n.population}
    - Households: ${n.households}
    - Median Income: $${n.medianIncome}
    - Median Home Price: $${n.medianHomePrice}
    - Affordability Ratio: ${n.affordabilityRatio} (Lower is more affordable)
    - Active Transport (Sustainable Mode %): ${n.sustainableModePct}%

    Provide a professional demographic and real estate summary for someone considering moving here.
    Also highlight 3 key unique points about its socio-economic standing in the city.
    Conclude with a specific recommendation based on its stats.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A 2-3 sentence overview." },
            keyHighlights: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "Three bullet points about unique characteristics."
            },
            recommendation: { type: Type.STRING, description: "Final verdict." }
          },
          required: ["summary", "keyHighlights", "recommendation"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as AnalysisResponse;
  } catch (error) {
    console.error("Gemini analysis failed:", error);
    throw error;
  }
};

import React from 'react';
import { Neighbourhood } from '../types';
import { COLOR_SCALE } from '../constants';

interface Props {
  neighbourhood: Neighbourhood;
  onClick: (n: Neighbourhood) => void;
  isSelected: boolean;
}

const NeighbourhoodCell: React.FC<Props> = ({ neighbourhood, onClick, isSelected }) => {
  const getColor = (pct: number) => {
    const index = Math.min(Math.floor((pct / 100) * COLOR_SCALE.length), COLOR_SCALE.length - 1);
    return COLOR_SCALE[index];
  };

  const bgColor = getColor(neighbourhood.sustainableModePct);

  // Dynamic contrast text color
  const isLight = neighbourhood.sustainableModePct < 40;
  const textColor = isLight ? 'text-slate-900' : 'text-white';

  return (
    <button
      onClick={() => onClick(neighbourhood)}
      className={`
        relative w-full aspect-[1/1.2] p-1 border border-slate-700/50 
        transition-all duration-200 group
        ${isSelected ? 'scale-110 z-10 shadow-2xl ring-2 ring-blue-400' : 'hover:scale-105 hover:z-10 hover:shadow-lg'}
      `}
      style={{ backgroundColor: bgColor }}
    >
      {/* Top Info */}
      <div className={`flex justify-between text-[6px] font-bold ${textColor} opacity-80 uppercase tracking-tighter`}>
        <span>{neighbourhood.type.slice(0, 3)}</span>
        <div className="text-right leading-none">
          {neighbourhood.population.toLocaleString()}
          <br />
          {neighbourhood.households.toLocaleString()}
        </div>
      </div>

      {/* Main Symbol */}
      <div className={`mt-1 text-2xl font-black ${textColor} leading-none tracking-tighter`}>
        {neighbourhood.symbol}
      </div>

      {/* Name */}
      <div className={`mt-0.5 text-[8px] font-bold ${textColor} leading-tight line-clamp-2 uppercase`}>
        {neighbourhood.name}
      </div>

      {/* Stats Bottom */}
      <div className="absolute bottom-1 left-1 right-1 flex justify-between items-end">
        <div className="flex flex-col">
          <span className={`text-[10px] font-black ${textColor}`}>{neighbourhood.affordabilityRatio.toFixed(1)}</span>
          <span className={`text-[5px] ${textColor} opacity-60 uppercase font-bold`}>Afford</span>
        </div>
        <div className="flex flex-col text-right">
          <span className={`text-[5px] ${textColor} font-bold`}>${Math.round(neighbourhood.medianIncome / 1000)}k HHI</span>
          <span className={`text-[5px] ${textColor} font-bold`}>${Math.round(neighbourhood.medianHomePrice / 1000)}k HP</span>
        </div>
      </div>
    </button>
  );
};

export default NeighbourhoodCell;

import React, { useState, useEffect } from 'react';
import { Neighbourhood, AnalysisResponse } from '../types';
import { analyzeNeighbourhood } from '../services/geminiService';

interface Props {
  neighbourhood: Neighbourhood | null;
  onClose: () => void;
}

const AnalysisPanel: React.FC<Props> = ({ neighbourhood, onClose }) => {
  const [analysis, setAnalysis] = useState<AnalysisResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (neighbourhood) {
      setLoading(true);
      setError(null);
      setAnalysis(null);
      analyzeNeighbourhood(neighbourhood)
        .then(res => setAnalysis(res))
        .catch(err => {
          console.error(err);
          setError("Failed to generate AI analysis. Please check your API configuration.");
        })
        .finally(() => setLoading(false));
    }
  }, [neighbourhood]);

  if (!neighbourhood) return null;

  return (
    <div className="fixed inset-y-0 right-0 w-full md:w-96 bg-slate-900 border-l border-slate-700 shadow-2xl z-50 flex flex-col transform transition-transform duration-300">
      <div className="p-6 border-b border-slate-700 flex justify-between items-center bg-slate-800/50">
        <div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{neighbourhood.name}</h2>
          <p className="text-blue-400 font-bold text-sm">Ward {neighbourhood.ward}</p>
        </div>
        <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
          <i className="fa-solid fa-xmark text-xl"></i>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        {/* Core Stats */}
        <div className="grid grid-cols-2 gap-4">
          <StatBox label="Affordability" value={neighbourhood.affordabilityRatio.toFixed(2)} sub="Ratio (HHI/HP)" icon="fa-hand-holding-dollar" />
          <StatBox label="Sustainable" value={`${neighbourhood.sustainableModePct}%`} sub="Active Transit" icon="fa-bicycle" />
          <StatBox label="Median HHI" value={`$${neighbourhood.medianIncome.toLocaleString()}`} sub="Household Income" icon="fa-wallet" />
          <StatBox label="Median HP" value={`$${neighbourhood.medianHomePrice.toLocaleString()}`} sub="Home Price" icon="fa-house-chimney" />
        </div>

        {/* AI Analysis Section */}
        <div className="space-y-4">
          <div className="flex items-center gap-2 text-indigo-400">
            <i className="fa-solid fa-wand-magic-sparkles"></i>
            <h3 className="text-xs font-black uppercase tracking-widest">Gemini AI Insights</h3>
          </div>

          {loading ? (
            <div className="space-y-3 py-4">
              <div className="h-4 bg-slate-800 rounded animate-pulse w-full"></div>
              <div className="h-4 bg-slate-800 rounded animate-pulse w-5/6"></div>
              <div className="h-4 bg-slate-800 rounded animate-pulse w-4/6"></div>
            </div>
          ) : error ? (
            <div className="p-4 bg-red-900/20 border border-red-800/50 rounded-lg text-red-400 text-xs italic">
              {error}
            </div>
          ) : analysis ? (
            <div className="space-y-6">
              <p className="text-slate-300 text-sm leading-relaxed italic">
                "{analysis.summary}"
              </p>

              <div className="space-y-3">
                <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Key Highlights</h4>
                <ul className="space-y-2">
                  {analysis.keyHighlights.map((point, i) => (
                    <li key={i} className="flex gap-3 text-xs text-slate-300">
                      <span className="text-indigo-500 font-bold mt-0.5">•</span>
                      {point}
                    </li>
                  ))}
                </ul>
              </div>

              <div className="p-4 bg-indigo-900/10 border border-indigo-800/30 rounded-lg">
                <h4 className="text-[10px] font-bold text-indigo-400 uppercase tracking-wider mb-2">Verdict</h4>
                <p className="text-xs font-medium text-slate-200">{analysis.recommendation}</p>
              </div>
            </div>
          ) : null}
        </div>
      </div>

      <div className="p-6 bg-slate-800/50 border-t border-slate-700">
        <p className="text-[10px] text-slate-500 leading-tight">
          Socio-economic data visualization based on historical Edmonton city datasets. 
          AI insights generated for general informational purposes.
        </p>
      </div>
    </div>
  );
};

const StatBox = ({ label, value, sub, icon }: { label: string, value: string, sub: string, icon: string }) => (
  <div className="bg-slate-800/40 p-4 rounded border border-slate-700/50">
    <div className="flex items-center gap-2 text-slate-400 mb-1">
      <i className={`fa-solid ${icon} text-[10px]`}></i>
      <span className="text-[9px] font-bold uppercase tracking-wider">{label}</span>
    </div>
    <div className="text-lg font-black text-white">{value}</div>
    <div className="text-[9px] text-slate-500 font-medium">{sub}</div>
  </div>
);

export default AnalysisPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { Neighbourhood, NeighbourhoodStats } from './types';
import { fetchNeighbourhoods, calculateStats } from './services/dataService';
import NeighbourhoodCell from './components/NeighbourhoodCell';
import AnalysisPanel from './components/AnalysisPanel';
import { COLOR_SCALE } from './constants';

const App: React.FC = () => {
  const [neighbourhoods, setNeighbourhoods] = useState<Neighbourhood[]>([]);
  const [selectedNeighbourhood, setSelectedNeighbourhood] = useState<Neighbourhood | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const data = fetchNeighbourhoods();
    setNeighbourhoods(data);
  }, []);

  const stats = useMemo(() => calculateStats(neighbourhoods), [neighbourhoods]);

  const filteredNeighbourhoods = useMemo(() => {
    return neighbourhoods.filter(n => 
      n.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      n.ward.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [neighbourhoods, searchQuery]);

  // Create a grid map for easier rendering
  // Row: 0-8, Col: 0-20
  const grid: (Neighbourhood | null)[][] = Array.from({ length: 9 }, () => Array(21).fill(null));
  filteredNeighbourhoods.forEach(n => {
    if (n.row >= 0 && n.row < 9 && n.col >= 0 && n.col < 21) {
      grid[n.row][n.col] = n;
    }
  });

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col">
      {/* Header */}
      <header className="p-6 bg-slate-900 border-b border-slate-800 sticky top-0 z-40">
        <div className="max-w-[1800px] mx-auto flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-600 rounded-lg flex items-center justify-center text-2xl font-black shadow-lg shadow-blue-900/50">Ed</div>
            <div>
              <h1 className="text-2xl font-black text-white uppercase tracking-tighter">Periodic Table of Edmonton</h1>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Neighbourhood Socio-Economic Grid</p>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row items-center gap-6">
            <div className="relative group w-full sm:w-80">
              <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-400 transition-colors"></i>
              <input 
                type="text" 
                placeholder="Search Neighbourhood or Ward..." 
                className="w-full bg-slate-800 border border-slate-700 rounded-full py-2.5 pl-11 pr-6 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>

            <div className="hidden lg:flex items-center gap-4 border-l border-slate-800 pl-6">
              <QuickStat label="N-Hoods" value={stats.totalNeighbourhoods.toString()} />
              <QuickStat label="Avg Afford" value={stats.avgAffordability.toFixed(1)} />
              <QuickStat label="Active Mode" value={`${stats.avgSustainableMode.toFixed(1)}%`} />
            </div>
          </div>
        </div>
      </header>

      {/* Main Table Area */}
      <main className="flex-1 overflow-x-auto p-6 md:p-10 select-none">
        <div className="max-w-[2400px] mx-auto relative">

          {/* Legend Overlay */}
          <div className="mb-10 flex flex-wrap items-center gap-8 bg-slate-900/40 p-6 rounded-2xl border border-slate-800/50">
            <div className="space-y-2">
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block">Sustainable Transport Range</span>
              <div className="flex items-center gap-0.5">
                <span className="text-[10px] text-slate-400 mr-2">Low</span>
                {COLOR_SCALE.map((c, i) => (
                  <div key={i} className="w-8 h-4 rounded-sm" style={{ backgroundColor: c }}></div>
                ))}
                <span className="text-[10px] text-slate-400 ml-2">High</span>
              </div>
            </div>

            <div className="space-y-1">
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block">X-Axis Mapping</span>
              <span className="text-xs text-slate-300 font-medium">Household Income Percentiles (0% → 100%)</span>
            </div>

            <div className="space-y-1">
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block">Y-Axis Mapping</span>
              <span className="text-xs text-slate-300 font-medium">Affordability Ratio (HHI / Home Price)</span>
            </div>
          </div>

          {/* Grid View */}
          <div className="periodic-grid min-w-[1600px]">
            {grid.map((row, rIdx) => (
              <React.Fragment key={rIdx}>
                {row.map((cell, cIdx) => (
                  <div key={`${rIdx}-${cIdx}`} className="min-h-[140px]">
                    {cell ? (
                      <NeighbourhoodCell 
                        neighbourhood={cell} 
                        onClick={setSelectedNeighbourhood}
                        isSelected={selectedNeighbourhood?.id === cell.id}
                      />
                    ) : (
                      <div className="w-full h-full border border-slate-900/20 rounded opacity-10"></div>
                    )}
                  </div>
                ))}
              </React.Fragment>
            ))}
          </div>

          {/* Row Labels (Vertical) */}
          <div className="absolute left-[-40px] top-[140px] bottom-0 flex flex-col justify-around text-slate-600 font-black text-[10px] uppercase pointer-events-none">
            {Array.from({length: 9}).map((_, i) => (
              <div key={i} className="rotate-[-90deg]">Ratio {i}</div>
            ))}
          </div>
        </div>
      </main>

      {/* Analysis Side Panel */}
      <AnalysisPanel 
        neighbourhood={selectedNeighbourhood} 
        onClose={() => setSelectedNeighbourhood(null)} 
      />

      {/* Footer */}
      <footer className="p-8 bg-slate-900 border-t border-slate-800">
        <div className="max-w-[1800px] mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <p className="text-slate-500 text-xs">
            &copy; 2024 YEG Urban Science Lab. Data provided for conceptual planning and visualization.
          </p>
          <div className="flex gap-6">
            <FooterLink icon="fa-github" label="Source" />
            <FooterLink icon="fa-database" label="Dataset" />
            <FooterLink icon="fa-robot" label="AI Engine" />
          </div>
        </div>
      </footer>
    </div>
  );
};

const QuickStat = ({ label, value }: { label: string, value: string }) => (
  <div className="text-center sm:text-left">
    <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest leading-none mb-1">{label}</div>
    <div className="text-lg font-black text-white leading-none">{value}</div>
  </div>
);

const FooterLink = ({ icon, label }: { icon: string, label: string }) => (
  <a href="#" className="flex items-center gap-2 text-slate-500 hover:text-blue-400 transition-colors text-xs font-bold uppercase tracking-wider">
    <i className={`fa-brands ${icon}`}></i>
    {label}
  </a>
);

export default App;

