      <header className="p-6 bg-slate-900 border-b border-slate-800 sticky top-0 z-40">
        <div className="max-w-[1800px] mx-auto flex flex-col xl:flex-row xl:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-600 rounded-lg flex items-center justify-center text-2xl font-black shadow-lg shadow-blue-900/50">Ed</div>
            <div>
              <h1 className="text-2xl font-black text-white uppercase tracking-tighter">Periodic Table of Edmonton</h1>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Neighbourhood Socio-Economic Grid</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row items-center gap-4 flex-1 justify-end">
            {/* View All Button - Just clears search */}
            <button 
              onClick={handleViewAll}
              className={`px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap border ${searchQuery === '' ? 'bg-slate-800 text-slate-500 border-slate-700' : 'bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 border-blue-500/30'}`}
              disabled={searchQuery === ''}
            >
              <i className="fa-solid fa-eye mr-2"></i> Show All {neighbourhoods.length}
            </button>

            {/* Layout Toggles */}
            <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
              <button 
                onClick={() => setViewMode('grid')}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'grid' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
              >
                <i className="fa-solid fa-table-cells mr-2"></i> Grid
              </button>
              <button 
                onClick={() => setViewMode('list')}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
              >
                <i className="fa-solid fa-list mr-2"></i> List
              </button>
            </div>

            {/* Search Bar */}
            <div className="relative group w-full md:w-80">
              <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-400 transition-colors"></i>
              <input 
                type="text" 
                placeholder="Search Name or Ward..." 
                className="w-full bg-slate-800 border border-slate-700 rounded-full py-2.5 pl-11 pr-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              {searchQuery && (
                <button 
                  onClick={() => setSearchQuery('')}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors"
                >
                  <i className="fa-solid fa-circle-xmark"></i>
                </button>
              )}
            </div>

            {/* Quick Stats */}
            <div className="hidden 2xl:flex items-center gap-4 border-l border-slate-800 pl-6">
              <QuickStat label="N-Hoods" value={stats.totalNeighbourhoods.toString()} />
              <QuickStat label="Avg Afford" value={stats.avgAffordability.toFixed(1)} />
              <QuickStat label="Active Mode" value={`${stats.avgSustainableMode.toFixed(1)}%`} />
            </div>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-x-auto p-6 md:p-10 select-none">
        <div className="max-w-[2400px] mx-auto relative">

          {viewMode === 'grid' ? (
            <>
              {/* Legend Overlay */}
              <div className="mb-10 flex flex-wrap items-center gap-8 bg-slate-900/40 p-6 rounded-2xl border border-slate-800/50">
                <div className="space-y-2">
                  <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block">Sustainable Transport Range</span>
                  <div className="flex items-center gap-0.5">
                    <span className="text-[10px] text-slate-400 mr-2">Low</span>
                    {COLOR_SCALE.map((c, i) => (
                      <div key={i} className="w-8 h-4 rounded-sm" style={{ backgroundColor: c }}></div>
                    ))}
                    <span className="text-[10px] text-slate-400 ml-2">High</span>
                  </div>
                </div>

                <div className="space-y-1">
                  <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block">X-Axis Mapping (Cols)</span>
                  <span className="text-xs text-slate-300 font-medium">Income Percentiles (20 Buckets)</span>
                </div>

                <div className="space-y-1">
                  <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest block">Y-Axis Mapping (Rows)</span>
                  <span className="text-xs text-slate-300 font-medium">Affordability Ratio (0 → 8+)</span>
                </div>
              </div>

              {/* Grid View */}
              <div className="periodic-grid min-w-[1600px]">
                {grid.map((row, rIdx) => (
                  <React.Fragment key={rIdx}>
                    {row.map((cellStack, cIdx) => (
                      <div key={`${rIdx}-${cIdx}`} className="min-h-[140px] relative">
                        {cellStack.length > 0 ? (
                          <div className="w-full h-full relative">
                            {/* If multiple elements share a slot, the first is primary, others indicated by badge */}
                            <NeighbourhoodCell 
                              neighbourhood={cellStack[0]} 
                              onClick={setSelectedNeighbourhood}
                              isSelected={selectedNeighbourhood?.id === cellStack[0].id}
                            />
                            {cellStack.length > 1 && (
                              <div className="absolute -top-1 -right-1 bg-yellow-500 text-slate-950 text-[8px] font-black px-1 rounded-sm shadow-lg pointer-events-none z-20">
                                +{cellStack.length - 1}
                              </div>
                            )}
                          </div>
                        ) : (
                          <div className="w-full h-full border border-slate-900/10 rounded opacity-5"></div>
                        )}
                      </div>
                    ))}
                  </React.Fragment>
                ))}
              </div>

              {/* Row Labels (Vertical) */}
              <div className="absolute left-[-40px] top-[140px] bottom-0 flex flex-col justify-around text-slate-700 font-black text-[9px] uppercase pointer-events-none">
                {Array.from({length: 9}).map((_, i) => (
                  <div key={i} className="rotate-[-90deg]">Ratio {i}</div>
                ))}
              </div>
            </>
          ) : (
            <div className="max-w-7xl mx-auto">
              <ListView 
                neighbourhoods={filteredNeighbourhoods} 
                onSelect={setSelectedNeighbourhood}
                selectedId={selectedNeighbourhood?.id}
              />
            </div>
          )}
        </div>
      </main>

      <AnalysisPanel 
        neighbourhood={selectedNeighbourhood} 
        onClose={() => setSelectedNeighbourhood(null)} 
      />

      <footer className="p-8 bg-slate-900 border-t border-slate-800">
        <div className="max-w-[1800px] mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <p className="text-slate-500 text-xs font-medium">
            &copy; 2024 YEG Urban Science Lab. All datasets reviewed and mapped.
          </p>
          <div className="flex gap-6">
            <FooterLink icon="fa-github" label="Source" />
            <FooterLink icon="fa-database" label="Dataset" />
            <FooterLink icon="fa-robot" label="AI Engine" />
          </div>
        </div>
      </footer>
    </div>
  );
};

const QuickStat = ({ label, value }: { label: string, value: string }) => (
  <div className="text-center sm:text-left">
    <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest leading-none mb-1">{label}</div>
