import { COLOR_SCALE } from '../constants';

interface Props {
  neighbourhood: Neighbourhood;
  onClick: (n: Neighbourhood) => void;
  isSelected: boolean;
}

/**
 * NeighbourhoodCell represents a single "element" in the Periodic Table.
 * Organized by Affordability (Rows) and Income (Columns).
 */
const NeighbourhoodCell: React.FC<Props> = ({ neighbourhood, onClick, isSelected }) => {
  const getColor = (pct: number) => {
    const index = Math.min(Math.floor((pct / 100) * COLOR_SCALE.length), COLOR_SCALE.length - 1);
    return COLOR_SCALE[index];
  };

  const bgColor = getColor(neighbourhood.sustainableModePct);

  // Dynamic contrast text color based on sustainable mode percentage (background brightness proxy)
  const isLight = neighbourhood.sustainableModePct < 40;
  const textColor = isLight ? 'text-slate-900' : 'text-white';

  return (
    <button
      onClick={() => onClick(neighbourhood)}
      className={`
        relative w-full aspect-[1/1.2] p-1 border border-slate-700/50 
        transition-all duration-200 group
        ${isSelected ? 'scale-110 z-10 shadow-2xl ring-2 ring-blue-400' : 'hover:scale-105 hover:z-10 hover:shadow-lg'}
      `}
      style={{ backgroundColor: bgColor }}
    >
      {/* Top Info Header: Zoning Type and Demographic Size - 8px (33% of 24px) */}
      <div className={`flex justify-between text-[8px] font-bold ${textColor} opacity-80 uppercase tracking-tighter`}>
        <span>{neighbourhood.type.slice(0, 3)}</span>
        <div className="text-right leading-none">
          Pop. {neighbourhood.population.toLocaleString()}
          <br />
          {neighbourhood.households.toLocaleString()}
        </div>
      </div>

      {/* Main Symbol: Ward Representation (24px) */}
      <div className={`mt-1 text-[24px] font-black ${textColor} leading-none tracking-tighter`}>
        {neighbourhood.symbol}
      </div>

      {/* Name: Neighbourhood Identity - 12px (50% of 24px) */}
      <div className={`mt-0.5 text-[12px] font-bold ${textColor} leading-tight line-clamp-2 uppercase tracking-tighter`}>
        {neighbourhood.name}
      </div>

      {/* Stats Footer: Affordability Ratio and Financial Metrics */}
      <div className="absolute bottom-1 left-1 right-1 flex justify-between items-end">
        <div className="flex flex-col items-start leading-none">
          {/* 18px (75% of 24px) */}
          <span className={`text-[18px] font-black ${textColor} leading-none`}>
            {neighbourhood.affordabilityRatio.toFixed(1)}
          </span>
          {/* Updated label to 'Affordability' - 8px (33% of 24px) */}
          <span className={`text-[8px] ${textColor} opacity-60 uppercase font-black tracking-tighter mt-0.5`}>
            Affordability
          </span>
        </div>
        <div className="flex flex-col text-right">
          {/* Values - 8px (33% of 24px) */}
          <span className={`text-[8px] ${textColor} font-bold`}>${Math.round(neighbourhood.medianIncome / 1000)}k HHI</span>
          <span className={`text-[8px] ${textColor} font-bold`}>${Math.round(neighbourhood.medianHomePrice / 1000)}k HP</span>
        </div>
      </div>
    </button>
  );
};

export default NeighbourhoodCell;

