import React, { useState, useEffect } from 'react';
import { Neighbourhood, AnalysisResponse } from '../types';
import { analyzeNeighbourhood } from '../services/geminiService';

interface Props {
  neighbourhood: Neighbourhood | null;
  onClose: () => void;
}

const AnalysisPanel: React.FC<Props> = ({ neighbourhood, onClose }) => {
  const [analysis, setAnalysis] = useState<AnalysisResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (neighbourhood) {
      setLoading(true);
      setError(null);
      setAnalysis(null);
      analyzeNeighbourhood(neighbourhood)
        .then(res => setAnalysis(res))
        .catch(err => {
          console.error(err);
          setError("Failed to generate AI analysis. Please check your API configuration.");
        })
        .finally(() => setLoading(false));
    }
  }, [neighbourhood]);

  if (!neighbourhood) return null;

  return (
    <div className="fixed inset-y-0 right-0 w-full md:w-96 bg-slate-900 border-l border-slate-700 shadow-2xl z-50 flex flex-col transform transition-transform duration-300">
      <div className="p-6 border-b border-slate-700 flex justify-between items-center bg-slate-800/50">
        <div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{neighbourhood.name}</h2>
          <p className="text-blue-400 font-bold text-sm">Ward {neighbourhood.ward}</p>
        </div>
        <button onClick={onClose} className="text-slate-300 hover:text-white transition-colors p-2" aria-label="Close panel">
          <i className="fa-solid fa-xmark text-xl"></i>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-8">
        {/* Core Stats */}
        <div className="grid grid-cols-2 gap-4">
          <StatBox label="Affordability" value={neighbourhood.affordabilityRatio.toFixed(2)} sub="Ratio (HHI/HP)" icon="fa-hand-holding-dollar" />
          <StatBox label="Sustainable" value={`${neighbourhood.sustainableModePct}%`} sub="Active Transit" icon="fa-bicycle" />
          <StatBox label="Median HHI" value={`$${neighbourhood.medianIncome.toLocaleString()}`} sub="Household Income" icon="fa-wallet" />
          <StatBox label="Median HP" value={`$${neighbourhood.medianHomePrice.toLocaleString()}`} sub="Home Price" icon="fa-house-chimney" />
        </div>

        {/* AI Analysis Section */}
        <div className="space-y-4">
          <div className="flex items-center gap-2 text-indigo-400">
            <i className="fa-solid fa-wand-magic-sparkles"></i>
            <h3 className="text-[10px] font-black uppercase tracking-widest">Gemini AI Insights</h3>
          </div>

          {loading ? (
            <div className="space-y-3 py-4">
              <div className="h-4 bg-slate-800 rounded animate-pulse w-full"></div>
              <div className="h-4 bg-slate-800 rounded animate-pulse w-5/6"></div>
              <div className="h-4 bg-slate-800 rounded animate-pulse w-4/6"></div>
            </div>
          ) : error ? (
            <div className="p-4 bg-red-900/40 border border-red-800/50 rounded-lg text-red-100 text-xs italic font-medium">
              {error}
            </div>
          ) : analysis ? (
            <div className="space-y-6">
              <p className="text-slate-100 text-sm leading-relaxed italic">
                "{analysis.summary}"
              </p>

              <div className="space-y-3">
                <h4 className="text-[10px] font-bold text-slate-300 uppercase tracking-wider">Key Highlights</h4>
                <ul className="space-y-2">
                  {analysis.keyHighlights.map((point, i) => (
                    <li key={i} className="flex gap-3 text-xs text-slate-200">
                      <span className="text-indigo-400 font-bold mt-0.5">•</span>
                      {point}
                    </li>
                  ))}
                </ul>
              </div>

              <div className="p-4 bg-indigo-900/30 border border-indigo-700/50 rounded-lg">
                <h4 className="text-[10px] font-black text-indigo-300 uppercase tracking-wider mb-2">Verdict</h4>
                <p className="text-xs font-bold text-slate-50">{analysis.recommendation}</p>
              </div>
            </div>
          ) : null}
        </div>
      </div>

      <div className="p-6 bg-slate-800 border-t border-slate-700">
        <p className="text-[10px] text-slate-300 font-medium leading-tight">
          Socio-economic data visualization based on historical Edmonton city datasets. 
          AI insights generated for general informational purposes.
        </p>
      </div>
    </div>
  );
};

const StatBox = ({ label, value, sub, icon }: { label: string, value: string, sub: string, icon: string }) => (
  <div className="bg-slate-800/60 p-4 rounded border border-slate-700/80 shadow-inner">
    <div className="flex items-center gap-2 text-slate-300 mb-1">
      <i className={`fa-solid ${icon} text-[10px]`}></i>
      <span className="text-[9px] font-black uppercase tracking-wider">{label}</span>
    </div>
    <div className="text-lg font-black text-white">{value}</div>
    <div className="text-[10px] text-slate-400 font-bold">{sub}</div>
  </div>
);

export default AnalysisPanel;

