import React from 'react';
import { Neighbourhood } from '../types';
import { COLOR_SCALE } from '../constants';

interface Props {
  neighbourhood: Neighbourhood;
  onClick: (n: Neighbourhood) => void;
  isSelected: boolean;
}

/**
 * Calculates perceived brightness to determine if white or black text should be used.
 * Formula: (R * 0.2126 + G * 0.7152 + B * 0.0722)
 */
const getPerceivedLuminance = (hex: string): number => {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return (r * 0.2126 + g * 0.7152 + b * 0.0722) / 255;
};

const NeighbourhoodCell: React.FC<Props> = ({ neighbourhood, onClick, isSelected }) => {
  const getColor = (pct: number) => {
    const index = Math.min(Math.floor((pct / 100) * COLOR_SCALE.length), COLOR_SCALE.length - 1);
    return COLOR_SCALE[index];
  };

  const bgColor = getColor(neighbourhood.sustainableModePct);

  // Perceived luminance threshold of 0.5 (Standard for AA accessibility)
  const luminance = getPerceivedLuminance(bgColor);
  const isLightBackground = luminance > 0.5;
  const textColor = isLightBackground ? 'text-slate-950' : 'text-white';

  return (
    <button
      onClick={() => onClick(neighbourhood)}
      className={`
        relative w-full aspect-[1/1.2] p-1 border border-slate-700/50 
        transition-all duration-200 group
        ${isSelected ? 'scale-110 z-10 shadow-2xl ring-2 ring-blue-400' : 'hover:scale-105 hover:z-10 hover:shadow-lg'}
      `}
      style={{ backgroundColor: bgColor }}
      aria-label={`${neighbourhood.name} neighbourhood details`}
    >
      {/* Top Info Header - Contrast Fixed (8px) */}
      <div className={`flex justify-between text-[8px] font-bold ${textColor} uppercase tracking-tighter`}>
        <span className="font-black">{neighbourhood.type.slice(0, 3)}</span>
        <div className="text-right leading-none">
          POP: {neighbourhood.population.toLocaleString()}
          <br />
          HH: {neighbourhood.households.toLocaleString()}
        </div>
      </div>

      {/* Main Symbol (24px - Meets AA Large Text Standards) */}
      <div className={`mt-1 text-[24px] font-black ${textColor} leading-none tracking-tighter`}>
        {neighbourhood.symbol}
      </div>

      {/* Name (12px - Bolded for legibility) */}
      <div className={`mt-0.5 text-[12px] font-extrabold ${textColor} leading-tight line-clamp-2 uppercase tracking-tighter`}>
        {neighbourhood.name}
      </div>

      {/* Stats Footer */}
      <div className="absolute bottom-1 left-1 right-1 flex justify-between items-end">
        <div className="flex flex-col items-start leading-none">
          <span className={`text-[18px] font-black ${textColor} leading-none`}>
            {neighbourhood.affordabilityRatio.toFixed(1)}
          </span>
          {/* Label removed as per user request to reduce clutter and maintain periodic table aesthetic */}
        </div>
        <div className="flex flex-col text-right leading-tight">
          <span className={`text-[8px] ${textColor} font-bold whitespace-nowrap`}>HHI: ${Math.round(neighbourhood.medianIncome / 1000)}k</span>
          <span className={`text-[8px] ${textColor} font-bold whitespace-nowrap`}>HP: ${Math.round(neighbourhood.medianHomePrice / 1000)}k</span>
        </div>
      </div>
    </button>
  );
};

