  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  useEffect(() => {
    const data = fetchNeighbourhoods();
    setNeighbourhoods(data);
  }, []);

  const stats = useMemo(() => calculateStats(neighbourhoods), [neighbourhoods]);

  const filteredNeighbourhoods = useMemo(() => {
    return neighbourhoods.filter(n => 
      n.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      n.ward.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [neighbourhoods, searchQuery]);

  const handleViewAll = () => {
    setSearchQuery('');
  };

  // Grid populated as 2D array of unique slots
  const grid: (Neighbourhood | null)[][] = Array.from({ length: 9 }, () => Array.from({ length: 21 }, () => null));

  filteredNeighbourhoods.forEach(n => {
    if (n.row >= 0 && n.row < 9 && n.col >= 0 && n.col < 21) {
      // If slot is taken, only the first one mapped wins (removing stacking)
      if (!grid[n.row][n.col]) {
        grid[n.row][n.col] = n;
