import React from 'react';
import { Neighbourhood } from '../types';
import { COLOR_SCALE } from '../constants';

interface Props {
  neighbourhood: Neighbourhood;
  onClick: (n: Neighbourhood) => void;
  onHover?: (n: Neighbourhood | null) => void;
  isSelected: boolean;
  isStatic?: boolean;
}

/**
 * Calculates perceived brightness to determine if white or black text should be used.
 * Formula: (R * 0.2126 + G * 0.7152 + B * 0.0722)
 */
const getPerceivedLuminance = (hex: string): number => {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return (r * 0.2126 + g * 0.7152 + b * 0.0722) / 255;
};

const NeighbourhoodCell: React.FC<Props> = ({ 
  neighbourhood, 
  onClick, 
  onHover, 
  isSelected,
  isStatic = false 
}) => {
  const getColor = (pct: number) => {
    const index = Math.min(Math.floor((pct / 100) * COLOR_SCALE.length), COLOR_SCALE.length - 1);
    return COLOR_SCALE[index];
  };

  const bgColor = getColor(neighbourhood.sustainableModePct);
  const luminance = getPerceivedLuminance(bgColor);
  const isLightBackground = luminance > 0.5;
  const textColor = isLightBackground ? 'text-slate-950' : 'text-white';
  const mutedTextColor = isLightBackground ? 'text-slate-900/70' : 'text-white/70';

  const containerClasses = `
    relative w-full aspect-[1/1.25] p-[8%] border border-slate-700/40 
    transition-all duration-200 ease-out flex flex-col items-stretch
    will-change-transform transform-gpu
    ${isStatic ? 'cursor-default pointer-events-none' : 'cursor-pointer hover:border-white/40 shadow-black/20'}
    ${isSelected ? 'ring-4 ring-blue-400 z-10 scale-105 shadow-2xl' : ''}
  `;

  return (
    <button
      onClick={() => !isStatic && onClick(neighbourhood)}
      onMouseEnter={() => !isStatic && onHover?.(neighbourhood)}
      onMouseLeave={() => !isStatic && onHover?.(null)}
      className={containerClasses}
      style={{ backgroundColor: bgColor }}
      aria-label={`${neighbourhood.name} neighbourhood details`}
      disabled={isStatic}
    >
      {/* 1. Header Row: Type and Population Metrics */}
      <div className={`flex justify-between items-start text-[2cqw] xl:text-[0.6rem] font-black ${textColor} uppercase tracking-tight leading-none h-[12%]`}>
        <span className="opacity-80 border-b border-current pb-0.5 whitespace-nowrap overflow-hidden">
          {neighbourhood.type.slice(0, 3)}
        </span>
        <div className="text-right flex flex-col">
          <span className="whitespace-nowrap">P: {neighbourhood.population.toLocaleString()}</span>
          <span className="whitespace-nowrap">H: {neighbourhood.households.toLocaleString()}</span>
        </div>
      </div>

      {/* 2. Middle Block: Symbol and Name */}
      <div className="flex-1 flex flex-col justify-center py-[4%]">
        <div className={`text-[8cqw] xl:text-[1.8rem] font-black ${textColor} leading-none tracking-tighter text-left mb-[4%]`}>
          {neighbourhood.symbol}
        </div>
        <div className={`text-[2.5cqw] xl:text-[0.65rem] font-black ${textColor} leading-tight line-clamp-2 uppercase tracking-tighter text-left`}>
          {neighbourhood.name}
        </div>
      </div>

      {/* 3. Footer Block: Affordability and Pricing */}
      <div className="mt-auto pt-[4%] border-t border-current/10 flex items-end justify-between">
        <div className="flex flex-col items-start">
          <span className={`text-[4cqw] xl:text-[1rem] font-black ${textColor} leading-none`}>
            {neighbourhood.affordabilityRatio.toFixed(1)}
          </span>
          <span className={`text-[1.5cqw] xl:text-[0.4rem] ${mutedTextColor} font-black uppercase tracking-widest`}>Ratio</span>
        </div>
        <div className="flex flex-col text-right leading-[1.1]">
          <span className={`text-[2cqw] xl:text-[0.5rem] ${textColor} font-bold whitespace-nowrap`}>
            ${Math.round(neighbourhood.medianIncome / 1000)}K
          </span>
          <span className={`text-[2cqw] xl:text-[0.5rem] ${textColor} font-bold whitespace-nowrap`}>
            ${Math.round(neighbourhood.medianHomePrice / 1000)}K
          </span>
        </div>
      </div>

      {/* Selection Indicator Dot */}
      {isSelected && (
        <div className="absolute -top-2 -right-2 w-[15%] h-[15%] max-w-[12px] max-h-[12px] bg-blue-500 rounded-full border-2 border-slate-950 shadow-lg z-[60]"></div>
      )}
    </button>
  );
};

