              <input 
                type="text" 
                placeholder="Search Name or Ward..." 
                className="w-full bg-slate-800 border border-slate-700 rounded-full py-2.5 pl-11 pr-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all placeholder:text-slate-500"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              {searchQuery && (
                <button 
