                </div>
              </div>

              {/* Grid View with Blur/Fade Filter */}
              <div 
                className={`periodic-grid min-w-[1600px] transition-all duration-500 ease-in-out transform-gpu ${
                  hoveredNeighbourhood ? 'opacity-50 blur-[4px]' : 'opacity-100 blur-0'
                }`}
              >
                {grid.map((row, rIdx) => (
                  <React.Fragment key={rIdx}>
                    {row.map((cell, cIdx) => (
                      <div key={`${rIdx}-${cIdx}`} className="min-h-[140px] relative">
                        {cell ? (
                          <NeighbourhoodCell 
