import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Neighbourhood, NeighbourhoodStats } from './types';
import { fetchNeighbourhoods, calculateStats } from './services/dataService';
import NeighbourhoodCell from './components/NeighbourhoodCell';
import ListView from './components/ListView';
import AnalysisPanel from './components/AnalysisPanel';
import { COLOR_SCALE } from './constants';

/**
 * Main Application Component
 */
const App: React.FC = () => {
  const [neighbourhoods, setNeighbourhoods] = useState<Neighbourhood[]>([]);
  const [selectedNeighbourhood, setSelectedNeighbourhood] = useState<Neighbourhood | null>(null);
  const [hoveredNeighbourhood, setHoveredNeighbourhood] = useState<Neighbourhood | null>(null);
  const [hoveredRect, setHoveredRect] = useState<{ top: number, left: number, width: number, height: number } | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  const mainScrollRef = useRef<HTMLElement>(null);
  const mousePos = useRef({ x: 0, y: 0 });
  const scrollRequestRef = useRef<number | null>(null);

  useEffect(() => {
    const data = fetchNeighbourhoods();
    setNeighbourhoods(data);
  }, []);

  // --- EDGE SCROLLING LOGIC ---
  useEffect(() => {
    const EDGE_THRESHOLD = 100; // Pixels from edge to trigger scroll
    const MAX_SPEED = 20; // Max pixels per frame

    const handleMouseMove = (e: MouseEvent) => {
      mousePos.current = { x: e.clientX, y: e.clientY };
      if (!scrollRequestRef.current) {
        scrollRequestRef.current = requestAnimationFrame(scrollLoop);
      }
    };

    const scrollLoop = () => {
      const { x, y } = mousePos.current;
      const { innerWidth, innerHeight } = window;
      const container = mainScrollRef.current;

      let dx = 0;
      let dy = 0;

      // Horizontal Scroll (targets the main container)
      if (container) {
        if (x < EDGE_THRESHOLD) {
          dx = -MAX_SPEED * (1 - x / EDGE_THRESHOLD);
        } else if (x > innerWidth - EDGE_THRESHOLD) {
          dx = MAX_SPEED * (1 - (innerWidth - x) / EDGE_THRESHOLD);
        }
        if (dx !== 0) container.scrollLeft += dx;
      }

      // Vertical Scroll (targets the window/body)
      if (y < EDGE_THRESHOLD) {
        dy = -MAX_SPEED * (1 - y / EDGE_THRESHOLD);
      } else if (y > innerHeight - EDGE_THRESHOLD) {
        dy = MAX_SPEED * (1 - (innerHeight - y) / EDGE_THRESHOLD);
      }
      if (dy !== 0) window.scrollBy(0, dy);

      // Continue loop if still in a scroll zone
      if (dx !== 0 || dy !== 0) {
        scrollRequestRef.current = requestAnimationFrame(scrollLoop);
      } else {
        scrollRequestRef.current = null;
      }
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      if (scrollRequestRef.current) cancelAnimationFrame(scrollRequestRef.current);
    };
  }, []);

  const stats = useMemo(() => calculateStats(neighbourhoods), [neighbourhoods]);

  const filteredNeighbourhoods = useMemo(() => {
    return neighbourhoods.filter(n => 
      n.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      n.ward.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [neighbourhoods, searchQuery]);

  const handleViewAll = () => {
    setSearchQuery('');
  };

  // Grid populated as 2D array of unique slots
  const grid: (Neighbourhood | null)[][] = Array.from({ length: 9 }, () => Array.from({ length: 21 }, () => null));

  filteredNeighbourhoods.forEach(n => {
    if (n.row >= 0 && n.row < 9 && n.col >= 0 && n.col < 21) {
      if (!grid[n.row][n.col]) {
        grid[n.row][n.col] = n;
      }
    }
  });

  const handleHover = (n: Neighbourhood | null, rect?: DOMRect) => {
    setHoveredNeighbourhood(n);
    if (n && rect) {
      setHoveredRect({
        top: rect.top,
        left: rect.left,
        width: rect.width,
        height: rect.height
      });
    } else {
      setHoveredRect(null);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col text-slate-200 overflow-x-hidden">
      {/* Header */}
      <header className="p-6 bg-slate-900 border-b border-slate-800 sticky top-0 z-40 shadow-xl">
        <div className="max-w-[1800px] mx-auto flex flex-col xl:flex-row xl:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-600 rounded-lg flex items-center justify-center text-2xl font-black shadow-lg shadow-blue-900/50 text-white">Ed</div>
            <div>
              <h1 className="text-2xl font-black text-white uppercase tracking-tighter">Periodic Table of Edmonton</h1>
              <p className="text-slate-300 text-xs font-bold uppercase tracking-widest">Neighbourhood Socio-Economic Grid</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row items-center gap-4 flex-1 justify-end">
            <button 
              onClick={handleViewAll}
              className={`px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap border ${searchQuery === '' ? 'bg-slate-800 text-slate-400 border-slate-700' : 'bg-blue-600/20 hover:bg-blue-600/30 text-blue-300 border-blue-500/50'}`}
              disabled={searchQuery === ''}
            >
              <i className="fa-solid fa-eye mr-2"></i> Show All {neighbourhoods.length}
            </button>

            <div className="flex bg-slate-800 p-1 rounded-lg border border-slate-700">
              <button 
                onClick={() => setViewMode('grid')}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'grid' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-300 hover:text-slate-100'}`}
              >
                <i className="fa-solid fa-table-cells mr-2"></i> Grid
              </button>
              <button 
                onClick={() => setViewMode('list')}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black uppercase tracking-widest transition-all ${viewMode === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-300 hover:text-slate-100'}`}
              >
                <i className="fa-solid fa-list mr-2"></i> List
              </button>
            </div>

            <div className="relative group w-full md:w-80">
              <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-400 transition-colors"></i>
              <input 
                type="text" 
                placeholder="Search Name or Ward..." 
                className="w-full bg-slate-800 border border-slate-700 rounded-full py-2.5 pl-11 pr-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all placeholder:text-slate-500"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              {searchQuery && (
                <button 
                  onClick={() => setSearchQuery('')}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-white transition-colors"
                >
                  <i className="fa-solid fa-circle-xmark"></i>
                </button>
              )}
            </div>

            <div className="hidden 2xl:flex items-center gap-4 border-l border-slate-800 pl-6">
              <QuickStat label="N-Hoods" value={stats.totalNeighbourhoods.toString()} />
              <QuickStat label="Avg Afford" value={stats.avgAffordability.toFixed(1)} />
              <QuickStat label="Active Mode" value={`${stats.avgSustainableMode.toFixed(1)}%`} />
            </div>
          </div>
        </div>
      </header>

      <main ref={mainScrollRef} className="flex-1 overflow-x-auto p-6 md:p-10 select-none scroll-smooth">
        <div className="max-w-[2400px] mx-auto relative">

          {viewMode === 'grid' ? (
            <>
              {/* Legend Overlay */}
              <div className="mb-10 flex flex-wrap items-center gap-8 bg-slate-900/60 p-6 rounded-2xl border border-slate-800 backdrop-blur-md">
                <div className="space-y-2">
                  <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest block">Sustainable Transport Range</span>
                  <div className="flex items-center gap-0.5">
                    <span className="text-[10px] text-slate-300 font-bold mr-2">Low</span>
                    {COLOR_SCALE.map((c, i) => (
                      <div key={i} className="w-8 h-4 rounded-sm border border-slate-800/50" style={{ backgroundColor: c }}></div>
                    ))}
                    <span className="text-[10px] text-slate-300 font-bold ml-2">High</span>
                  </div>
                </div>

                <div className="space-y-1">
                  <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest block">X-Axis Mapping (Cols)</span>
                  <span className="text-xs text-slate-200 font-bold">Sustainable Mode % (20 Buckets)</span>
                </div>

                <div className="space-y-1">
                  <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest block">Y-Axis Mapping (Rows)</span>
                  <span className="text-xs text-slate-200 font-bold">Affordability Ratio (0 → 8+)</span>
                </div>
              </div>

              {/* Grid View with Blur/Fade Filter */}
              <div 
                className={`periodic-grid min-w-[1600px] transition-all duration-500 ease-in-out transform-gpu ${
                  hoveredNeighbourhood ? 'opacity-50 blur-[4px]' : 'opacity-100 blur-0'
                }`}
              >
                {grid.map((row, rIdx) => (
                  <React.Fragment key={rIdx}>
                    {row.map((cell, cIdx) => (
                      <div key={`${rIdx}-${cIdx}`} className="min-h-[140px] relative">
                        {cell ? (
                          <NeighbourhoodCell 
                            neighbourhood={cell} 
                            onClick={setSelectedNeighbourhood}
                            onHover={handleHover}
                            isSelected={selectedNeighbourhood?.id === cell.id}
                          />
                        ) : (
                          <div className="w-full h-full border border-slate-900/40 rounded opacity-10"></div>
                        )}
                      </div>
                    ))}
                  </React.Fragment>
                ))}
              </div>

              {/* Row Labels */}
              <div className="absolute left-[-40px] top-[140px] bottom-0 flex flex-col justify-around text-slate-400 font-black text-[10px] uppercase pointer-events-none opacity-40">
                {Array.from({length: 9}).map((_, i) => (
                  <div key={i} className="rotate-[-90deg]">Rank {i}</div>
                ))}
              </div>
            </>
          ) : (
            <div className="max-w-7xl mx-auto">
              <ListView 
                neighbourhoods={filteredNeighbourhoods} 
                onSelect={setSelectedNeighbourhood}
                selectedId={selectedNeighbourhood?.id}
              />
            </div>
          )}
        </div>
      </main>

      {/* Magnified Sliding Center Preview Overlay */}
      {hoveredNeighbourhood && hoveredRect && viewMode === 'grid' && (
        <div className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center bg-slate-950/20 backdrop-blur-[2px] animate-in fade-in duration-300">
           <div 
            className="shadow-[0_40px_100px_rgba(0,0,0,0.9)] border-4 border-white/20 transform-gpu overflow-hidden rounded-sm transition-all duration-500 ease-out"
            style={{ 
              width: '12vw',
              minWidth: '240px',
              animation: 'slide-to-center 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards',
              '--source-x': `${hoveredRect.left}px`,
              '--source-y': `${hoveredRect.top}px`,
              '--source-w': `${hoveredRect.width}px`,
              '--source-h': `${hoveredRect.height}px`,
            } as React.CSSProperties}
           >
              <NeighbourhoodCell 
                neighbourhood={hoveredNeighbourhood} 
                onClick={() => {}} 
                isSelected={false}
                isStatic
              />
           </div>

           <style dangerouslySetInnerHTML={{ __html: `
              @keyframes slide-to-center {
                from {
                  position: fixed;
                  top: var(--source-y);
                  left: var(--source-x);
                  width: var(--source-w);
                  height: var(--source-h);
                  transform: scale(1);
                  opacity: 0.8;
                }
                to {
                  position: fixed;
                  top: 50%;
                  left: 50%;
                  transform: translate(-50%, -50%) scale(1);
                  width: 12vw;
                  height: auto;
                  opacity: 1;
                }
              }
           `}} />
        </div>
      )}

      <AnalysisPanel 
        neighbourhood={selectedNeighbourhood} 
        onClose={() => setSelectedNeighbourhood(null)} 
      />

      <footer className="p-8 bg-slate-900 border-t border-slate-800">
        <div className="max-w-[1800px] mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <p className="text-slate-300 text-xs font-bold">
            &copy; 2024 YEG Urban Science Lab. All datasets reviewed and mapped.
          </p>
          <div className="flex gap-6">
            <FooterLink icon="fa-github" label="Source" />
            <FooterLink icon="fa-database" label="Dataset" />
            <FooterLink icon="fa-robot" label="AI Engine" />
          </div>
        </div>
      </footer>
    </div>
  );
};

