          <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">
            Edmonton Periodic Table &bull; Use Ctrl + Scroll or Pinch to Zoom &bull; Scroll to Edges to Pan
          </p>
        </div>
      </footer>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes slide-to-center {
          from {
            position: fixed;
            top: var(--source-y);
            left: var(--source-x);
            width: var(--source-w);
            height: var(--source-h);
            opacity: 0;
            transform: scale(0.8);
          }
          to {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%) scale(1);
            width: 18vw;
            height: auto;
            opacity: 1;
          }
        }
      `}} />
    </div>
  );
};

