import React, { useState, useMemo } from 'react';
import { Neighbourhood } from '../types';

interface Props {
  neighbourhoods: Neighbourhood[];
  onSelect: (n: Neighbourhood) => void;
  selectedId?: string;
}

type SortKey = 'name' | 'ward' | 'medianIncome' | 'medianHomePrice' | 'affordabilityRatio' | 'sustainableModePct' | 'symbol';
type SortDirection = 'asc' | 'desc';

interface SortConfig {
  key: SortKey;
  direction: SortDirection;
}

/**
 * ListView component provides a structured table view of all neighbourhoods.
 * Features interactive header sorting and data visualization for metrics.
 */
const ListView: React.FC<Props> = ({ neighbourhoods, onSelect, selectedId }) => {
  const [sortConfig, setSortConfig] = useState<SortConfig>({ 
    key: 'name', 
    direction: 'asc' 
  });

  const requestSort = (key: SortKey) => {
    let direction: SortDirection = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const sortedData = useMemo(() => {
    const sortableData = [...neighbourhoods];
    sortableData.sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];

      if (typeof aValue === 'string' && typeof bValue === 'string') {
        return sortConfig.direction === 'asc' 
          ? aValue.localeCompare(bValue) 
          : bValue.localeCompare(aValue);
      }

      if (typeof aValue === 'number' && typeof bValue === 'number') {
        return sortConfig.direction === 'asc' 
          ? aValue - bValue 
          : bValue - aValue;
      }

      return 0;
    });
    return sortableData;
  }, [neighbourhoods, sortConfig]);

  if (neighbourhoods.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-slate-400">
        <i className="fa-solid fa-magnifying-glass text-4xl mb-4 opacity-40"></i>
        <p className="text-sm font-black uppercase tracking-widest">No neighbourhoods found</p>
      </div>
    );
  }

  const SortHeader = ({ label, sortKey, align = 'left' }: { label: string, sortKey: SortKey, align?: 'left' | 'right' }) => (
    <th className={`px-6 py-4 text-[10px] font-black text-slate-100 uppercase tracking-widest ${align === 'right' ? 'text-right' : 'text-left'}`}>
      <button 
        onClick={() => requestSort(sortKey)}
        className={`inline-flex items-center gap-2 hover:text-blue-400 transition-colors group ${align === 'right' ? 'flex-row-reverse' : 'flex-row'}`}
      >
        {label}
        <span className="flex flex-col text-[8px] opacity-40 group-hover:opacity-100">
          <i className={`fa-solid fa-caret-up ${sortConfig.key === sortKey && sortConfig.direction === 'asc' ? 'text-blue-500 opacity-100' : ''}`}></i>
          <i className={`fa-solid fa-caret-down ${sortConfig.key === sortKey && sortConfig.direction === 'desc' ? 'text-blue-500 opacity-100' : ''}`}></i>
        </span>
      </button>
    </th>
  );

  return (
    <div className="overflow-x-auto rounded-xl border border-slate-800 bg-slate-900/50 backdrop-blur-sm">
      <table className="w-full text-left border-collapse">
        <thead>
          <tr className="bg-slate-800 border-b border-slate-700">
            <SortHeader label="Sym" sortKey="symbol" />
            <SortHeader label="Neighbourhood" sortKey="name" />
            <SortHeader label="Ward" sortKey="ward" />
            <SortHeader label="Income" sortKey="medianIncome" align="right" />
            <SortHeader label="Home Price" sortKey="medianHomePrice" align="right" />
            <SortHeader label="Affordability" sortKey="affordabilityRatio" align="right" />
            <SortHeader label="Sustainable" sortKey="sustainableModePct" align="right" />
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-800">
          {sortedData.map((n) => (
            <tr 
              key={n.id} 
              onClick={() => onSelect(n)}
              className={`
                group cursor-pointer transition-colors
                ${selectedId === n.id ? 'bg-blue-600/20' : 'hover:bg-slate-800/40'}
              `}
            >
              <td className="px-6 py-4">
                <span className="inline-flex items-center justify-center w-10 h-10 rounded bg-slate-800 text-lg font-black text-white border border-slate-700 group-hover:border-blue-500 transition-colors">
                  {n.symbol}
                </span>
              </td>
              <td className="px-6 py-4">
                <div className="text-sm font-black text-white uppercase tracking-tight">{n.name}</div>
                <div className="text-[10px] text-slate-300 font-bold uppercase tracking-wider">{n.type}</div>
              </td>
              <td className="px-6 py-4">
                <span className="text-xs font-bold text-slate-200">{n.ward}</span>
              </td>
              <td className="px-6 py-4 text-right">
                <span className="text-sm font-mono font-bold text-white">${n.medianIncome.toLocaleString()}</span>
              </td>
              <td className="px-6 py-4 text-right">
                <span className="text-sm font-mono font-bold text-white">${n.medianHomePrice.toLocaleString()}</span>
              </td>
              <td className="px-6 py-4 text-right">
                <span className={`text-sm font-black ${n.affordabilityRatio > 6 ? 'text-red-300' : 'text-emerald-400'}`}>
                  {n.affordabilityRatio.toFixed(2)}
                </span>
              </td>
              <td className="px-6 py-4 text-right">
                <div className="flex items-center justify-end gap-2">
                   <div className="w-16 h-2 bg-slate-800 rounded-full overflow-hidden border border-slate-700">
                     <div 
                      className="h-full bg-blue-500" 
                      style={{ width: `${n.sustainableModePct}%` }}
                    />
                   </div>
                   <span className="text-xs font-black text-slate-100 w-8">{Math.round(n.sustainableModePct)}%</span>
                </div>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

